namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;

    private readonly List<Notification> _notifications =
    [
        new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)),
        new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-15)),
        new(3, "New feature available: dark mode.", DateTime.UtcNow.AddMinutes(-5)),
    ];

    /// <summary>Returns the current snapshot of notifications.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given id.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_notifications)
        {
            var newer = _notifications.Where(n => n.Id > lastSeenId).ToList();
            return Task.FromResult(newer);
        }
    }

    /// <summary>Simulates an external system adding a notification.</summary>
    public void AddRandom()
    {
        string[] messages =
        [
            "Deployment completed successfully.",
            "New comment on your pull request.",
            "Disk usage exceeded 80%.",
            "Build #42 passed.",
            "Scheduled maintenance tonight at 10 PM.",
            "A new user signed up.",
        ];

        lock (_notifications)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService Svc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification>? PersistedNotifications { get; set; }

    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        // Restore from prerender state if available; otherwise load from service.
        PersistedNotifications ??= await Svc.GetNotificationsAsync();
        notifications = PersistedNotifications;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        // Seed a fake notification every 5 s so there is something to find.
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            Svc.AddRandom();

            var lastId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
            var newer = await Svc.GetNotificationsSinceAsync(lastId);

            if (newer.Count > 0)
            {
                notifications.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

